class Account:
    def __init__(self, balance):
        self.balance = balance

    def summary(self):
        return f"{self.balance}: ${self.balance}"

    def withdraw(self, amount):
        if amount > 0 and amount <= self.balance:
            self.balance -= amount
            return True
        return False

    def deposit(self, amount):
        self.balance += amount
        return self.balance
